// scripts/add-required-fields.js
/**
 * Append `<ModelName>Required = ["field1", "field2", ...]` constants
 * to every model file generated by openapi-typescript-codegen.
 */

const fs = require("fs");
const path = require("path");

const MODELS_DIR = path.resolve("./src/api/models");

function extractRequiredFields(content) {
  const match = content.match(/export type (\w+) = \{([\s\S]*?)\n\};/);
  if (!match) return null;

  const [, modelName, body] = match;
  const required = [];
  const lines = body.split("\n");

  for (const line of lines) {
    const trimmed = line.trim();
    const fieldMatch = trimmed.match(/^(\w+):/);
    const isOptional = trimmed.includes("?:") || trimmed.includes("| null");
    if (fieldMatch && !isOptional) {
      required.push(fieldMatch[1]);
    }
  }

  return { modelName, required };
}

function addRequiredConstants() {
  if (!fs.existsSync(MODELS_DIR)) return;
  const files = fs.readdirSync(MODELS_DIR).filter(f => f.endsWith(".ts"));

  for (const file of files) {
    const filePath = path.join(MODELS_DIR, file);
    const content = fs.readFileSync(filePath, "utf8");
    const parsed = extractRequiredFields(content);
    if (!parsed || parsed.required.length === 0) continue;

    const { modelName, required } = parsed;
    const constDecl = `\nexport const ${modelName}Required = ${JSON.stringify(required)} as const;\n`;

    if (!content.includes(`${modelName}Required`)) {
      fs.appendFileSync(filePath, constDecl);
      console.log(`✅ Added ${modelName}Required → [${required.join(", ")}]`);
    }
  }
}

addRequiredConstants();

// Patch OpenAPI.ts: use env var with localhost fallback
const OPENAPI_CONFIG = path.resolve("./src/api/core/OpenAPI.ts");
if (fs.existsSync(OPENAPI_CONFIG)) {
  let content = fs.readFileSync(OPENAPI_CONFIG, "utf8");
  const patched = content.replace(
    /BASE: process\.env\.NEXT_PUBLIC_API_BASE_URL \|\| "[^"]*"/,
    "BASE: process.env.NEXT_PUBLIC_API_BASE_URL || 'http://localhost:8000'"
  );
  if (patched !== content) {
    fs.writeFileSync(OPENAPI_CONFIG, patched);
    console.log("✅ Patched OpenAPI.ts BASE → process.env.NEXT_PUBLIC_API_BASE_URL || 'http://localhost:8000'");
  }
}
